validators.command:
python3 -c "import re, pathlib; failed=[]; files=['social-plus-sdk/getting-started/platform-setup/web/web-quick-start.mdx','social-plus-sdk/getting-started/platform-setup/mobile/ios-quick-start.mdx','social-plus-sdk/getting-started/platform-setup/mobile/android-quick-start.mdx','social-plus-sdk/getting-started/platform-setup/mobile/flutter-quick-start.mdx']
for f in files:
  t=pathlib.Path(f).read_text()
  if not re.search(r'^## Initialize the SDK\b', t, re.M): failed.append(f'{f}: missing "## Initialize the SDK" heading')
  body=re.search(r'## Initialize the SDK(.*?)(?=\n## |\Z)', t, re.DOTALL)
  if body and not re.search(r'```\w+', body.group(1)): failed.append(f'{f}: Initialize section has no fenced code block')
flutter_len=len(pathlib.Path('social-plus-sdk/getting-started/platform-setup/mobile/flutter-quick-start.mdx').read_text().splitlines())
if flutter_len<150: failed.append(f'flutter-quick-start.mdx: only {flutter_len} lines, expected >150')
print('\n'.join(failed) if failed else 'OK'); import sys; sys.exit(1 if failed else 0)"
